<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop Clone</title>
    <style>
        :root {
            --ubuntu-orange: #e95420;
            --ubuntu-purple: #300a24;
            --ubuntu-dark: #2c001e;
            --window-bg: #3d3d3d;
            --taskbar-bg: rgba(0, 0, 0, 0.6);
            --text-color: #eeeeee;
        }

        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        body, html {
            width: 100%;
            height: 100%;
            overflow: hidden;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, var(--ubuntu-dark) 0%, var(--ubuntu-purple) 100%);
            position: relative;
            overflow: hidden;
        }

        /* Taskbar/Dock */
        #taskbar {
            position: absolute;
            bottom: 10px;
            left: 50%;
            transform: translateX(-50%);
            background: var(--taskbar-bg);
            backdrop-filter: blur(10px);
            padding: 8px 15px;
            border-radius: 20px;
            display: flex;
            gap: 15px;
            align-items: center;
            z-index: 1000;
            border: 1px solid rgba(255, 255, 255, 0.1);
        }

        .launcher-btn {
            background: none;
            border: none;
            cursor: pointer;
            font-size: 24px;
            transition: transform 0.2s;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        .launcher-btn:hover {
            transform: scale(1.2);
        }

        /* Window Styles */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background: var(--window-bg);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #555;
        }

        .window-header {
            background: #2d2d2d;
            padding: 8px 12px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: move;
            user-select: none;
        }

        .window-title {
            color: var(--text-clear);
            font-size: 14px;
            font-weight: bold;
            color: #ccc;
        }

        .win-close {
            background: #e95420;
            border: none;
            width: 14px;
            height: 14px;
            border-radius: 50%;
            cursor: pointer;
        }

        .window-content {
            flex: 1;
            padding: 10px;
            color: white;
            overflow: auto;
        }

        /* Files App Styles */
        #files-path {
            font-family: monospace;
            background: rgba(0,0,0,0.3);
            padding: 5px;
            margin-bottom: 10px;
            border-radius: 4px;
            font-size: 13px;
        }

        #files-up {
            cursor: pointer;
            background: #555;
            border: none;
            color: white;
            padding: 2px 8px;
            margin-bottom: 10px;
            border-radius: 3px;
        }

        .fs-list {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
            gap: 15px;
        }

        .fs-item {
            display: flex;
            flex-direction: column;
            align-items: center;
            text-align: center;
            cursor: pointer;
            font-size: 12px;
            padding: 5px;
            border-radius: 4px;
        }

        .fs-item:hover {
            background: rgba(255, 255, 255, 0.1);
        }

        .fs-icon {
            font-size: 32px;
            margin-bottom: 5px;
        }

        /* Notepad Styles */
        #tabs {
            display: flex;
            background: #222;
            padding: 5px 5px 0 5px;
            gap: 2px;
        }

        .tab {
            padding: 6px 12px;
            background: #444;
            color: #aaa;
            border-radius: 5px 5px 0 0;
            cursor: pointer;
            font-size: 13px;
            white-space: nowrap;
        }

        .tab.active {
            background: var(--window-bg);
            color: white;
        }

        #new-tab {
            background: none;
            border: none;
            color: white;
            font-size: 18px;
            cursor: pointer;
            padding: 0 5px;
        }

        #editor {
            width: 100%;
            height: 100%;
            background: var(--window-bg);
            color: #eee;
            border: none;
            resize: none;
            padding: 10px;
            font-family: 'Courier New', Courier, monospace;
            outline: none;
        }

        .hidden {
            display: none !important;
        }
    </style>
</head>
<body>

<div id="desktop">
    <!-- Taskbar -->
    <div id="taskbar">
        <button id="open-files" class="launcher-btn" title="Files">📁</button>
        <button id="open-notepad" class="launcher-btn" title="Notepad">📝</button>
    </div>

    <!-- Files Window -->
    <div id="files-window" class="window hidden" style="top: 50px; left: 50px; width: 500px; height: 350px;">
        <div class="window-header">
            <span class="window-title">Files</span>
            <button class="win-close"></button>
        </div>
        <div class="window-content">
            <button id="files-up">↑ Up</button>
            <div id="files-path">/</div>
            <div id="fs-container" class="fs-list">
                <!-- Files injected here -->
            </div>
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window hidden" style="top: 100px; left: 150px; width: 450px; height: 350px;">
        <div class="window-header">
            <span class="window-title">Notepad</span>
            <button class="win-close"></button>
        </div>
        <div id="tabs">
            <!-- Tabs injected here -->
            <button id="new-tab">+</button>
        </div>
        <div class="window-content" style="padding: 0;">
            <textarea id="editor"></textarea>
        </div>
    </div>
</div>

<script>
    /** --- FILESYSTEM LOGIC --- **/
    const filesystem = {
        '/': ['bin', 'etc', 'home', 'usr', 'var'],
        '/bin': [],
        '/etc': [],
        '/home': ['user'],
        '/home/user': ['Documents', 'Downloads', 'Pictures'],
        '/home/user/Documents': ['notes.txt', 'todo.md'],
        '/home/user/Downloads': [],
        '/home/user/Pictures': ['vacation.jpg'],
        '/usr': [],
        '/var': []
    };

    let currentPath = '/';

    const fsContainer = document.getElementById('fs-container');
    const filesPathDisplay = document.getElementById('files-path');
    const filesUpBtn = document.getElementById('files-up');

    function renderFiles() {
        fsContainer.innerHTML = '';
        filesPathDisplay.innerText = currentPath;

        const items = filesystem[currentPath] || [];

        items.forEach(name => {
            const fullPath = currentPath === '/' ? `/${name}` : `${currentPath}/${name}`;
            const isDir = !!filesystem[fullPath];

            const itemEl = document.createElement('div');
            itemEl.className = 'fs-item';
            itemEl.innerHTML = `
                <span class="fs-icon">${isDir ? '📁' : '📄'}</span>
                <span>${name}</span>
            `;

            // Double click to enter folder
            itemEl.ondblclick = () => {
                if (isDir) {
                    currentPath = fullPath;
                    renderFiles();
                }
            };

            fsContainer.appendChild(itemEl);
        });
    }

    filesUpBtn.onclick = () => {
        if (currentPath === '/') return;
        const parts = currentPath.split('/').filter(p => p !== '');
        parts.pop();
        currentlarPath = '/' + parts.join('/'); // Error in variable name, fixed below
        // Re-calculating path correctly:
        let newPath = currentPath.substring(0, currentPath.lastIndexOf('/'));
        currentPath = newPath === '' ? '/' : newPath;
        renderFiles();
    };

    /** --- NOTEPAD LOGIC --- **/
    let tabs = [];
    let activeTabId = null;

    const notepadWindow = document.getElementById('notepad-window');
    const tabsContainer = document.getElementById('tabs');
    const newTabBtn = document.getElementById('new-tab');
    const editor = document.getElementById('editor');

    function initNotepad() {
        const saved = localStorage.getItem('ubuntu_notepad_data');
        if (saved) {
            const data = JSON.parse(saved);
            tabs = data.tabs;
            activeTabId = data.activeTabId;
        } else {
            const initialId = Date.now();
            tabs = [{ id: initialId, title: 'Untitled', content: '' }];
            activeTabId = initialId;
        }
        renderTabs();
        switchTab(activeTabId);
    }

    function saveNotepad() {
        localStorage.setItem('ubuntu_notepad_data', JSON.stringify({
            tabs,
            activeTabId
        }));
    }

    function renderTabs() {
        // Clear existing tabs (keep the + button)
        const existingTabs = tabsContainer.querySelectorAll('.tab');
        existingTabs.forEach(t => t.remove());

        tabs.forEach(tab => {
            const tabEl = document.createElement('div');
            tabEl.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
            tabEl.innerText = tab.title;
            tabEl.onclick = () => switchTab(tab.id);
            tabsContainer.insertBefore(tabEl, newTabBtn);
        });
    }

    function switchTab(id) {
        activeTabId = id;
        const tab = tabs.find(t => t.id === id);
        editor.value = tab ? tab.content : '';
        renderTabs();
        saveNotepad();
    }

    newTabBtn.onclick = () => {
        const newId = Date.now();
        tabs.push({ id: newId, title: 'Untitled', content: '' });
        activeTabId = newId;
        renderTabs();
        switchTab(newId);
        saveNotepad();
    };

    editor.oninput = (e) => {
        const tab = tabs.find(t => t.id === activeTabId);
        if (tab) {
            tab.content = e.target.value;
            // Update title if it's the first line
            const firstLine = tab.content.split('\n')[0].substring(0, 15);
            tab.title = firstLine === '' ? 'Untitled' : firstLine;
            saveNotepad();
            // We don't re-render tabs on every keystroke to avoid losing focus, 
            // but we update the title in the background. 
            // To keep UI snappy, we only refresh tab text labels occasionally or on switch.
        }
    };

    // Update tab titles when switching away
    const originalSwitch = switchTab;
    switchTab = (id) => {
        // Before switching, update the title of the current tab based on content
        const currentTab = tabs.find(t => t.id === activeTabId);
        if (currentTab && currentTab.content) {
            const firstLine = currentTab.content.split('\n')[0].substring(0, 15);
            currentTab.title = firstLine === '' ? 'Untitled' : firstLine;
        }
        originalSwitch(id);
    };

    /** --- WINDOW MANAGEMENT --- **/
    function setupWindow(winId, launcherId) {
        const win = document.getElementById(winId);
        const launcher = document.getElementById(launcherId);
        const closeBtn = win.querySelector('.win-close');
        const header = win.querySelector('.window-header');

        launcher.onclick = () => win.classList.remove('hidden');
        closeBtn.onclick = () => win.classList.add('hidden');

        // Dragging logic
        let isDragging = false;
        let offsetX, offsetY;

        header.onmousedown = (e) => {
            isDragging = true;
            offsetX = e.clientX - win.offsetLeft;
            offsetY = e.clientY - win.offsetTop;
            win.style.zIndex = 100; // Bring to front
        };

        document.onmousemove = (e) => {
            if (!isDragging) return;
            win.style.left = (e.clientX - offsetX) + 'px';
            win.style.top = (e.clientY - offsetY) + 'px';
        };

        document.onmouseup = () => {
            isDragging = false;
        };
    }

    // Initialize everything
    window.onload = () => {
        renderFiles();
        initNotepad();
        setupWindow('files-window', 'open-files');
        setupWindow('notepad-window', 'open-notepad');
    };
</script>

</body>
</html>
